wp_send_json_success(
				array(
					'content' => $content,
					'title'   => esc_html__( 'Link Existing Field Groups', 'acf' ),
				)
			)

printf(
							/* translators: %s: The invalid search term */
							acf_esc_html( __( "No search results for '%s'", 'acf' ) ),
							'<span class="acf-invalid-search-term"></span>'
						)

printf(
							/* translators: %s: A link to the popular fields used in ACF */
							acf_esc_html( __( 'Try a different search term or browse %s', 'acf' ) ),
							$browse_popular_link //phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped
						)

printf(
							/* translators: %1$s current db version, %2$s available db version */
							esc_html__( 'Site requires database upgrade from %1$s to %2$s', 'acf' ),
							esc_html( acf_get_db_version() ),
							esc_html( ACF_VERSION )
						)

printf(
						/* translators: %s: The invalid search term */
						esc_html__( "No search results for '%s'", 'acf' ),
						'<span class="acf-invalid-icon-list-search-term"></span>'
					)

array_filter(
				$tabs,
				function ( $tab ) use ( $field ) {
					return in_array( $tab, $field['tabs'], true );
				},
				ARRAY_FILTER_USE_KEY
			)

wp_send_json_error(
					array(
						'error' => sprintf( __( 'User unable to add new %s', 'acf' ), $taxonomy_label ),
					)
				)

array_filter(
			acf_get_field_groups( $args ),
			function ( $group ) use ( $scope ) {
				if ( $scope and ! in_array( $group['key'], $scope ) ) {
					return false;
				}

				return $group['show_in_rest'];
			}
		)

array_filter(
			acf_get_fields( $field_group ),
			function ( $field ) {
				$field_type = acf_get_field_type( $field['type'] );
				return isset( $field_type->show_in_rest ) && $field_type->show_in_rest;
			}
		)

wp_send_json_success(
					array(
						'valid'  => 0,
						'errors' => array(
							array(
								'input'   => false,
								'message' => $nonce_error,
								'action'  => array(
									'label' => __( 'Learn more', 'acf' ),
									'url'   => acf_add_url_utm_tags( 'https://www.advancedcustomfields.com/resources/validation-nonce-errors/', 'docs', 'validation-nonce' ),
								),
							),
						),
					)
				)

wp_send_json_error(
				new WP_Error(
					'acf_invalid_permissions',
					__( 'Sorry, you do not have permission to do that.', 'acf' )
				)
			)

array_filter(
				$uncovered_properties,
				function ( $property ) use ( $type_chain, $property_domains ) {
					if ( ! isset( $property_domains[ $property ] ) ) {
						return true;
					}
					$valid_types = $property_domains[ $property ];
					return empty( array_intersect( $type_chain, $valid_types ) );
				}
			)

array_filter(
				$options_pages,
				function ( $options_page ) use ( $ui_options_page_slugs ) {
					return ! in_array( $options_page['menu_slug'], $ui_options_page_slugs, true );
				}
			)

